import { VexClient, VexViolationError } from 'vex-sdk';
import { ChatOpenAI } from '@langchain/openai';
import { ChatPromptTemplate } from '@langchain/core/prompts';
import { StringOutputParser } from '@langchain/core/output_parsers';
import { RunnableSequence } from '@langchain/core/runnables';
import { StructuredOutputParser } from 'langchain/output_parsers';
import { z } from 'zod';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  project: 'nextjs-langchain-app',
  environment: process.env.NODE_ENV,
});

const productSchema = z.object({
  name: z.string(),
  price: z.number(),
  sku: z.string(),
  inStock: z.boolean(),
});

const outputParser = StructuredOutputParser.fromZodSchema(productSchema);

const extractionChain = RunnableSequence.from([
  ChatPromptTemplate.fromMessages([
    ['system', 'Extract product information from the following text. {format_instructions}'],
    ['human', '{text}'],
  ]),
  new ChatOpenAI({ model: 'gpt-4o', temperature: 0 }),
  outputParser,
]);

export async function POST(request: Request) {
  const { text } = await request.json();

  try {
    const result = await vex.verify(
      {
        chainId: 'product-extraction',
        checks: ['output_schema_validation', 'hallucination', 'prompt_injection'],
        input: { text },
      },
      async (session) => {
        const output = await extractionChain.invoke({
          text,
          format_instructions: outputParser.getFormatInstructions(),
        });
        session.recordOutput(output);
        return output;
      }
    );

    return Response.json({ success: true, product: result });
  } catch (error) {
    if (error instanceof VexViolationError) {
      return Response.json(
        { success: false, error: error.message, check: error.checkName },
        { status: 422 }
      );
    }
    throw error;
  }
}
